import React, { useState, useEffect } from 'react';
import './AddPurchase.css';

const AddOutflow = ({ handleAdd, locations, materials }) => {
  const initialOutflowState = {
    location: '',
    materialid: '',
    materialname: '',
    quantity: '',
    width: null,
    lotnumber: '',
  };

  const [newOutflow, setNewOutflow] = useState(initialOutflowState);
  const [showExtras, setShowExtras] = useState(false);
  const [availableMaterials, setAvailableMaterials] = useState([]);
  const [availableWidths, setAvailableWidths] = useState([]);
  const [availableLots, setAvailableLots] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      if (newOutflow.location) {
        try {
          const responseMaterial = await fetch(`http://localhost:8081/purchasesAPI/materialid/${newOutflow.location}`);
          const dataList = await responseMaterial.json();
          const datamat = materials.find(material => material.id === newOutflow.materialid || '');

          if (dataList && datamat.extras === 1) {
            setShowExtras(true);
          } else {
            setShowExtras(false);
          }

          setAvailableMaterials(dataList.materials || []); // Update available materials
          setAvailableWidths([]); // Reset available widths
          setAvailableLots([]); // Reset available lots
          setNewOutflow((prevOutflow) => ({
            ...prevOutflow,
            materialid: '', // Reset material ID
            materialname: '', // Reset material name
            width: null, // Reset width
            lotnumber: '', // Reset lot number
          }));
        } catch (error) {
          console.error('Error fetching material list:', error);
        }
      } else {
        setShowExtras(false);
        setAvailableMaterials([]);
        setAvailableWidths([]);
        setAvailableLots([]);
        setNewOutflow((prevPurchase) => ({
          ...prevPurchase,
          materialid: '',
          materialname: '',
          width: null,
          lotnumber: '',
        }));
      }
    };

    fetchData();
  }, [newOutflow.location, newOutflow.materialid, materials]);
  
  

  const handleMaterialChange = (e) => {
    const selectedMaterialId = e.target.value;
    setNewOutflow((prevOutflow) => ({
      ...prevOutflow,
      materialid: selectedMaterialId,
      materialname: availableMaterials.find(material => material.id === selectedMaterialId)?.name || '',
      width: null, // Reset width
      lotnumber: '', // Reset lot number
    }));
  
    if (showExtras) {
      fetch(`http://localhost:8081/PurchasesAPI/widths/${newOutflow.location}/${selectedMaterialId}`)
        .then((response) => response.json())
        .then((widthsData) => {
          setAvailableWidths(widthsData);
          setAvailableLots([]);
        })
        .catch((error) => {
          console.error('Error fetching available widths:', error);
        });
    }
  };
  
  const handleWidthChange = (e) => {
    const selectedWidth = e.target.value;
    setNewOutflow((prevOutflow) => ({
      ...prevOutflow,
      width: selectedWidth,
      lotnumber: '', // Reset lot number
    }));
  
    // Fetch available lots for the selected material and width
    fetch(`http://localhost:8081/PurchasesAPI/lots/${newOutflow.location}/${newOutflow.materialid}/${selectedWidth}`)
      .then((response) => response.json())
      .then((lotsData) => {
        setAvailableLots(lotsData);
      })
      .catch((error) => {
        console.error('Error fetching available lots:', error);
      });
  };


  const handleChange = (e) => {
    const { name, value } = e.target;
    setNewOutflow((prevOutflow) => ({
      ...prevOutflow,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {

      handleAdd(newOutflow);

      setNewOutflow(initialOutflowState);
    } catch (error) {
      console.error('Error handling the form submission:', error);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="add-purchase-form">
      <div>
        <label>Location:</label>
        <select name="location" value={newOutflow.location} onChange={handleChange} required>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>
      {newOutflow.location && (
        <div>
          <div>
            <label>Material ID:</label>
            <input type="text" name="materialid" value={newOutflow.materialid} onChange={handleMaterialChange} required />
          </div>
          <div>
            <label>Material Name:</label>
            <input type="text" name="materialname" value={newOutflow.materialname} readOnly required />
          </div>
        </div>
      )}
      {newOutflow.materialid && showExtras && (
        <div>
          <label>Width:</label>
          <select
            name="width"
            value={newOutflow.width || ''}
            onChange={handleWidthChange}
            required
          >
            <option value="">Select a width</option>
            {availableWidths.map((width) => (
              <option key={width} value={width}>
                {width}
              </option>
            ))}
          </select>
        </div>
      )}
      {newOutflow.width && showExtras && (
        <div>
          <label>LOT#:</label>
          <select
            name="lotnumber"
            value={newOutflow.lotnumber || ''}
            onChange={handleChange}
            required
          >
            <option value="">Select a lot</option>
            {availableLots.map((lot) => (
              <option key={lot} value={lot}>
                {lot}
              </option>
            ))}
          </select>
        </div>
      )}
      <div>
        <label>Quantity:</label>
        <input type="text" name="quantity" value={newOutflow.quantity} onChange={handleChange} required />
      </div>
      <button type="submit" className="add_purchase_btn">
        Add Outflow
      </button>
    </form>
  );
};

export default AddOutflow;
